const evidence = readJson('data/dishwasher-fault-evidence.json');
const taxonomy = readJson('data/dishwasher-fault-taxonomy.json');
const errorCodeRegistry = readJson('data/dishwasher-error-codes.json');
const evidenceById = new Map(evidence.records.map((x)=>[x.id,x]));
const manifestByPage = new Map(manifest.pages.map((x)=>[x.page,x]));
const taxonomyByPage = new Map(taxonomy.symptoms.map((x)=>[x.slug,x]));

